SELECT name, diameter, mean_temperature 
FROM planets 
WHERE diameter = (SELECT MAX(diameter) FROM planets);

SELECT AVG(mass) 
FROM planets 
WHERE discovery_date < '2000-01-01';

SELECT planets.name 
FROM planets
JOIN rings ON planets.planet_id = rings.planet_id;

SELECT p.*, m.mission_id, m.first_visit_date, m.mission_type, m.launch_date, m.mission_status, m.mission_duration, m.mission_objectives, m.mission_outcomes, m.mission_images, m.research_papers
FROM planets p
LEFT JOIN missions m ON p.planet_id = m.planet_id;

SELECT name, mass
FROM planets
ORDER BY mass DESC;

SELECT * 
FROM moons 
WHERE diameter = (SELECT MIN(diameter) FROM moons);

SELECT p.name AS planet_name, m.name AS moon_name, m.mean_temperature
FROM planets p
LEFT JOIN moons m ON p.planet_id = m.planet_id;

SELECT name, mean_temperature 
FROM planets 
WHERE mean_temperature > (SELECT AVG(mean_temperature) FROM planets);
